#include <iostream>
#include <string>
#include <vector>

// Base class (parent)
class Enemy {
protected:
    std::string name;
    int health;
    int maxHealth;
    int attackPower;
    int defense;
    bool isAlive;

public:
    Enemy(std::string n, int h, int a, int d) {
        name = n;
        health = h;
        maxHealth = h;
        attackPower = a;
        defense = d;
        isAlive = true;
        std::cout << "Enemy " << name << " spawned!" << std::endl;
    }

    virtual ~Enemy() {}

    // Virtual method — can be overridden by derived classes
    virtual void attack(Enemy& target) {
        int damage = attackPower - (target.getDefense() / 2);
        if (damage < 0) damage = 0;
        std::cout << name << " attacks for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    virtual void takeDamage(int damage) {
        health -= damage;
        if (health <= 0) {
            health = 0;
            isAlive = false;
            std::cout << name << " has been defeated!" << std::endl;
        } else {
            std::cout << name << " took " << damage << " damage! (" << health << "/" << maxHealth << ")" << std::endl;
        }
    }

    virtual void displayStats() const {
        std::cout << "=== " << name << " ===" << std::endl;
        std::cout << "Health: " << health << "/" << maxHealth << std::endl;
        std::cout << "Attack: " << attackPower << std::endl;
        std::cout << "Defense: " << defense << std::endl;
        std::cout << "Status: " << (isAlive ? "Alive" : "Defeated") << std::endl;
    }

    // Getters
    std::string getName() const { return name; }
    int getHealth() const { return health; }
    int getDefense() const { return defense; }
    bool getIsAlive() const { return isAlive; }
};

// Derived class (child) — Boss inherits from Enemy
class Boss : public Enemy {
private:
    std::string specialMove;
    int rageMode;

public:
    Boss(std::string n, int h, int a, int d, std::string move) 
        : Enemy(n, h, a, d) {  // Call parent constructor
        specialMove = move;
        rageMode = 0;
        std::cout << "Boss " << name << " has arrived!" << std::endl;
    }

    // Override attack method
    void attack(Enemy& target) override {
        // If health is low, enter rage mode
        if (health < maxHealth * 0.3) {
            rageMode++;
            if (rageMode == 1) {
                std::cout << "⚡ " << name << " enters RAGE MODE! ⚡" << std::endl;
            }
            // Deal extra damage in rage mode
            int bonusDamage = 10 * rageMode;
            int damage = attackPower + bonusDamage - (target.getDefense() / 2);
            if (damage < 0) damage = 0;
            std::cout << name << " attacks with rage for " << damage << " damage!" << std::endl;
            target.takeDamage(damage);
        } else {
            // Normal attack
            int damage = attackPower - (target.getDefense() / 2);
            if (damage < 0) damage = 0;
            std::cout << name << " attacks for " << damage << " damage!" << std::endl;
            target.takeDamage(damage);
        }

        // Special move when health drops below 50%
        if (health < maxHealth * 0.5 && health > 0) {
            std::cout << "💥 " << name << " uses " << specialMove << "! 💥" << std::endl;
            // Special move damages all targets (would hit party in a real game)
        }
    }

    void displayStats() const override {
        Enemy::displayStats();  // Call parent version first
        std::cout << "Special Move: " << specialMove << std::endl;
        std::cout << "Rage Mode: " << (rageMode > 0 ? "ACTIVE!" : "Inactive") << std::endl;
    }
};

int main() {
    std::cout << "=== Inheritance: Enemy → Boss ===" << std::endl;

    // Create enemies
    Enemy goblin("Goblin", 30, 8, 3);
    Boss dragon("Dragon", 150, 25, 10, "Flame Breath");

    goblin.displayStats();
    dragon.displayStats();

    std::cout << "\n=== Combat ===" << std::endl;

    // Goblin attacks dragon
    goblin.attack(dragon);

    // Dragon attacks goblin
    dragon.attack(goblin);

    // Dragon attacks again
    dragon.attack(goblin);

    std::cout << "\n=== Final Stats ===" << std::endl;
    goblin.displayStats();
    dragon.displayStats();

    return 0;
}

