#include <iostream>
#include <string>

class Character {
protected:
    std::string name;
    int health;
    int attack;

public:
    Character(std::string n, int h, int a) {
        name = n;
        health = h;
        attack = a;
    }

    virtual ~Character() {}

    virtual void attack(Character& target) {
        std::cout << name << " attacks for " << attack << " damage!" << std::endl;
        target.takeDamage(attack);
    }

    virtual void takeDamage(int damage) {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage!" << std::endl;
    }

    virtual void displayStats() const {
        std::cout << name << " - Health: " << health << std::endl;
    }
};

class Warrior : public Character {
private:
    int rage;

public:
    Warrior(std::string n, int h, int a, int r) : Character(n, h, a) {
        rage = r;
    }

    void attack(Character& target) override {
        int totalAttack = attack + rage;
        std::cout << name << " (Warrior) attacks with rage for " << totalAttack << " damage!" << std::endl;
        target.takeDamage(totalAttack);
    }

    void displayStats() const override {
        Character::displayStats();
        std::cout << "Rage: " << rage << std::endl;
    }
};

int main() {
    Character goblin("Goblin", 50, 10);
    Warrior hero("Aragorn", 100, 20, 15);

    std::cout << "=== Initial Stats ===" << std::endl;
    goblin.displayStats();
    hero.displayStats();

    std::cout << "\n=== Combat ===" << std::endl;
    hero.attack(goblin);

    std::cout << "\n=== Final Stats ===" << std::endl;
    goblin.displayStats();
    hero.displayStats();

    return 0;
}
